      interview: [
        { level: "Junior", q: "What are Q objects?", a: "They allow you to construct complex queries with logic like OR, AND, and NOT within a single filter() call.", type: "Conceptual" },
        { level: "Junior", q: "What is an F object?", a: "It represents the value of a model field at the database level, allowing you to perform operations like 'likes = F('likes') + 1'.", type: "Conceptual" },
        { level: "Junior", q: "Difference between aggregate() and annotate()?", a: "aggregate() returns a summary of the whole QuerySet (e.g., total sum). annotate() returns a new QuerySet where each item has a derived field.", type: "Conceptual" },
        { level: "Junior", q: "How do you perform an OR query in Django?", a: "Using the '|' operator with Q objects: MyModel.objects.filter(Q(a=1) | Q(b=2)).", type: "Coding" },
        { level: "Junior", q: "How do you perform a NOT query in Django?", a: "Using the '~' operator with Q objects: MyModel.objects.filter(~Q(status='draft')).", type: "Coding" },
        { level: "Junior", q: "What is an 'Aggregation'?", a: "A calculation performed over a group of rows (e.g., Sum, Count, Avg).", type: "Conceptual" },
        { level: "Junior", q: "What is an 'Annotation'?", a: "Adding a calculated field to each individual record in a QuerySet.", type: "Conceptual" },
        { level: "Junior", q: "How do you get the number of records using aggregation?", a: "MyModel.objects.aggregate(Count('id')).", type: "Coding" },
        { level: "Junior", q: "How do you get the maximum value of a field?", a: "MyModel.objects.aggregate(Max('price')).", type: "Coding" },
        { level: "Junior", q: "How do you add a count of related objects to each record?", a: "MyModel.objects.annotate(num_related=Count('related_set')).", type: "Coding" },
        { level: "Junior", q: "What is 'F('id')'?", a: "An F-expression representing the primary key field of the current row in a database-level calculation.", type: "Conceptual" },
        { level: "Junior", q: "Why use F objects for incrementing counters?", a: "To avoid race conditions and ensure the increment happens atomically in the database.", type: "Conceptual" },
        { level: "Junior", q: "What is the return type of aggregate()?", a: "A dictionary containing the calculated values.", type: "Conceptual" },
        { level: "Junior", q: "What is the return type of annotate()?", a: "A QuerySet where each object has extra attributes.", type: "Conceptual" },
        { level: "Junior", q: "How do you import aggregation functions?", a: "from django.db.models import Sum, Count, Avg, etc.", type: "Coding" },
        { level: "Junior", q: "Can you use F objects in order_by()?", a: "Yes, e.g., order_by(F('my_field').desc(nulls_last=True)).", type: "Conceptual" },
        { level: "Mid", q: "How do you write an 'OR' query in Django?", a: "Using Q objects: Model.objects.filter(Q(name='A') | Q(name='B')).", type: "Coding" },
        { level: "Mid", q: "Why use F objects to update a counter field?", a: "Because it performs the addition in the database, avoiding race conditions where two processes might read the same old value.", type: "Conceptual" },
        { level: "Mid", q: "Explain Subqueries in Django ORM.", a: "They allow you to use the result of one QuerySet inside another, often used within annotations.", type: "Conceptual" },
        { level: "Mid", q: "What is the purpose of OuterRef?", a: "It's used within a Subquery to refer to a field from the 'outer' or main QuerySet.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'ExpressionWrapper'.", a: "It's used to wrap an expression and specify the output_field, which is necessary when combining different field types in a calculation.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle conditional choices in annotations?", a: "Using 'Case' and 'When' expressions from django.db.models.", type: "Coding" },
        { level: "Mid", q: "What is 'Coalesce' and why use it?", a: "It returns the first non-null value. Useful for providing defaults in annotations (e.g., Coalesce(Sum('related__total'), 0)).", type: "Scenario" },
        { level: "Mid", q: "Difference between Sum and Count in aggregation?", a: "Count counts the number of rows/objects; Sum adds up the values of a specific numeric field.", type: "Conceptual" },
        { level: "Mid", q: "How do you annotate with the length of a string field?", a: "Using the 'Length' function: annotate(len=Length('title')).", type: "Coding" },
        { level: "Mid", q: "Explain the 'Value' expression.", a: "It wraps a Python constant so it can be used in a Django database expression.", type: "Conceptual" },
        { level: "Mid", q: "How do you filter a QuerySet based on a value compared to another field?", a: "MyModel.objects.filter(price__gt=F('original_price')).", type: "Coding" },
        { level: "Mid", q: "What is 'Greatest' and 'Least'?", a: "Expressions that take a list of fields/expressions and return the maximum or minimum value among them for each row.", type: "Conceptual" },
        { level: "Senior", q: "How would you find all users who have more than 5 posts using annotate() and filter()?", a: "User.objects.annotate(num_posts=Count('post')).filter(num_posts__gt=5).", type: "Coding" },
        { level: "Senior", q: "What is the 'Exists' expression used for?", a: "An optimized Subquery that checks for the existence of related objects returning a Boolean.", type: "Conceptual" },
        { level: "Senior", q: "Explain the performance cost of multiple annotations.", a: "Each annotation often adds an extra JOIN or Subquery to the SQL, which can significantly slow down the query if not used carefully.", type: "Scenario" },
        { level: "Senior", q: "How do you handle conditional aggregation (e.g., sum of only active orders)?", a: "Using Case, When, and Then expressions within an annotate() or aggregate() call.", type: "Coding" },
        { level: "Senior", q: "What is the difference between Q(a=1, b=2) and Q(a=1) & Q(b=2)?", a: "They are logically identical (both are AND operations).", type: "Conceptual" },
        { level: "Senior", q: "How would you optimize a query that calculates complex stats for millions of rows?", a: "Using database views, denormalization (storing aggregates), or specific database indexes (like functional indexes).", type: "Scenario" },
        { level: "Senior", q: "Explain 'Window Functions' in the context of Django annotations.", a: "They allow calculations across a set of table rows that are somehow related to the current row (e.g., running total).", type: "Conceptual" },
        { level: "Senior", q: "How do you implement a 'Rank' in Django QuerySet?", a: "Using annotate(rank=Window(expression=Rank(), order_by=...)).", type: "Coding" },
        { level: "Senior", q: "Explain 'Subquery' versus 'JOIN' performance in Django.", a: "JOINs are often faster but Subqueries can be more flexible for certain calculations (like selecting the latest related record's status).", type: "Scenario" },
        { level: "Senior", q: "How do you use 'Extract' to group by year in an annotation?", a: "annotate(year=ExtractYear('created_at')).values('year').annotate(count=Count('id')).", type: "Coding" },
        { level: "Senior", q: "Explain 'Cast' in Django expressions.", a: "Allows you to convert a field's database type to another type (e.g., Integer to Float) for calculations.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle 'Race Conditions' in Django using advanced ORM features?", a: "Using F-expressions for atomic updates and 'select_for_update' for locking rows during complex logic.", type: "Scenario" },
        { level: "Senior", q: "What is the 'FilteredRelation' class?", a: "Introduced in Django 2.0, it allows you to specify JOIN conditions with extra filters, essentially creating a 'filtered JOIN'.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement full-text search weighting using Django Postgres search features?", a: "By using 'SearchQuery' and 'SearchRank' with specific weightings (A, B, C, D) assigned to different fields.", type: "Coding" },
        { level: "Senior", q: "Explain the difference between .aggregate() and .annotate() when used with .values().", a: "annotate() after values() acts like a 'GROUP BY'. aggregate() always collapses the whole result set into one dictionary.", type: "Conceptual" },
        { level: "Senior", q: "How do you avoid 'Circular Dependency' when using models in subquery annotations?", a: "By using app-label string references or importing models inside the function/method where the query is constructed.", type: "Scenario" },
        { level: "Senior", q: "Explain 'SQL Injection' risks in F-expressions.", a: "F-expressions are safe because Django handles the field names and parameters; risks only arise with raw SQL fragments in .extra().", type: "Conceptual" }
      ]
